// resources/js/pages/Components/Navigation.tsx
import { Bars3Icon, XMarkIcon } from '@heroicons/react/24/outline';

import { Link } from '@inertiajs/react';
import { useState } from 'react';

import { useScroll } from '@/hooks/useScroll';

interface NavLink {
  label: string;
  href: string;
  type: 'link' | 'anchor';
}

const Navigation = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState<boolean>(false);
  const { isScrolled } = useScroll(50);

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
    document.body.style.overflow = isMobileMenuOpen ? '' : 'hidden';
  };

  const closeMobileMenu = () => {
    setIsMobileMenuOpen(false);
    document.body.style.overflow = '';
  };

  const scrollTo = (sectionId: string) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
    closeMobileMenu();
  };

  const navLinks: NavLink[] = [
    { label: 'Formations', href: '/formations', type: 'link' },
    { label: 'Pourquoi CAB', href: '#avantages', type: 'anchor' },
    { label: 'Campus', href: '#campus', type: 'anchor' },
    { label: 'Contact', href: '#contact', type: 'anchor' },
  ];

  return (
    <>
      {/* Skip Link */}
      <a
        href="#contenu-principal"
        className="sr-only focus:not-sr-only focus:fixed focus:top-16 focus:left-4 focus:z-[9999] focus:bg-white focus:p-4 focus:rounded-xl focus:shadow-lg focus:text-cab-blue"
      >
        Aller au contenu principal
      </a>

      {/* Navigation */}
      <nav
        className={`
          fixed top-0 left-0 right-0 z-50
          transition-all duration-300
          ${isScrolled
            ? 'bg-white/95 backdrop-blur-md shadow-sm py-3'
            : 'bg-transparent py-4'
          }
        `}
        role="navigation"
        aria-label="Navigation principale"
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex items-center justify-between">

          {/* Logo */}
          <Link
            href="/"
            className="flex items-center shrink-0"
            aria-label="CAB Informatique - Accueil"
          >
            <img
              src="/assets/images/logo.jpeg"
              alt="CAB Informatique"
              className="h-12 w-auto object-contain"
              loading="lazy"
            />
          </Link>

          {/* Navigation Desktop */}
          <ul className="hidden md:flex items-center gap-8 list-none" role="menubar">
            {navLinks.map((link) => (
              <li key={link.label} role="none">
                {link.type === 'link' ? (
                  <Link
                    href={link.href}
                    className={`
                      text-sm font-medium transition-colors relative
                      after:content-[''] after:absolute after:bottom-[-4px] after:left-0
                      after:w-0 after:h-0.5 after:bg-cab-blue after:transition-all after:duration-300
                      hover:after:w-full
                      ${isScrolled
                        ? 'text-gray-600 hover:text-cab-blue'
                        : 'text-white/90 hover:text-white'
                      }
                    `}
                    role="menuitem"
                  >
                    {link.label}
                  </Link>
                ) : (
                  <button
                    onClick={() => scrollTo(link.href.replace('#', ''))}
                    className={`
                      text-sm font-medium transition-colors relative
                      after:content-[''] after:absolute after:bottom-[-4px] after:left-0
                      after:w-0 after:h-0.5 after:bg-cab-blue after:transition-all after:duration-300
                      hover:after:w-full
                      ${isScrolled
                        ? 'text-gray-600 hover:text-cab-blue'
                        : 'text-white/90 hover:text-white'
                      }
                    `}
                    role="menuitem"
                  >
                    {link.label}
                  </button>
                )}
              </li>
            ))}
          </ul>

          {/* Actions */}
          <div className="flex items-center gap-3">
            {/* Connexion */}
            <button
              className={`
                hidden md:inline-flex items-center gap-2 px-5 py-2.5
                rounded-full text-sm font-semibold
                border-2 transition-all cursor-pointer
                ${isScrolled
                  ? 'border-gray-200 text-gray-600 hover:border-cab-blue hover:text-cab-blue hover:bg-blue-50'
                  : 'border-white/30 text-white hover:border-white hover:bg-white/10'
                }
              `}
              aria-label="Se connecter"
            >
              🔑 Connexion
            </button>

            {/* Certification */}
            <Link
              href="/certification"
              className="inline-flex items-center gap-2 px-5 py-2.5 bg-cab-blue text-white rounded-full text-sm font-semibold hover:bg-cab-dark hover:-translate-y-0.5 hover:shadow-lg transition-all cursor-pointer no-underline"
            >
              📝 Certification
            </Link>

            {/* Hamburger Mobile */}
            <button
              onClick={toggleMobileMenu}
              className="md:hidden p-1 bg-none border-none cursor-pointer"
              aria-label={isMobileMenuOpen ? 'Fermer le menu mobile' : 'Ouvrir le menu mobile'}
              aria-expanded={isMobileMenuOpen}
            >
              {isMobileMenuOpen ? (
                <XMarkIcon className={`w-7 h-7 ${isScrolled ? 'text-gray-900' : 'text-white'}`} />
              ) : (
                <Bars3Icon className={`w-7 h-7 ${isScrolled ? 'text-gray-900' : 'text-white'}`} />
              )}
            </button>
          </div>

        </div>
      </nav>

      {/* Menu Mobile */}
      {isMobileMenuOpen && (
        <>
          {/* Overlay */}
          <div
            className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm md:hidden"
            onClick={closeMobileMenu}
            aria-hidden="true"
          />

          {/* Menu Panel */}
          <div
            className="fixed top-0 right-0 z-40 w-full max-w-sm h-full bg-white shadow-2xl md:hidden animate-slide-in-right"
            role="menu"
            aria-label="Menu mobile"
          >
            {/* En-tête */}
            <div className="flex items-center justify-between p-4 border-b border-gray-100">
              <img
                src="/assets/images/logo.jpeg"
                alt="CAB Informatique"
                className="h-10 w-auto object-contain"
                loading="lazy"
              />
              <button
                onClick={closeMobileMenu}
                className="p-2 hover:bg-gray-100 rounded-full transition-colors"
                aria-label="Fermer le menu"
              >
                <XMarkIcon className="w-6 h-6 text-gray-900" />
              </button>
            </div>

            {/* Liens */}
            <ul className="flex flex-col p-4 space-y-2 list-none">
              {navLinks.map((link) => (
                <li key={link.label} role="none">
                  {link.type === 'link' ? (
                    <Link
                      href={link.href}
                      onClick={closeMobileMenu}
                      className="block px-4 py-3 rounded-xl text-sm font-medium text-gray-700 hover:bg-blue-50 hover:text-cab-blue transition-colors"
                      role="menuitem"
                    >
                      {link.label}
                    </Link>
                  ) : (
                    <button
                      onClick={() => scrollTo(link.href.replace('#', ''))}
                      className="block w-full text-left px-4 py-3 rounded-xl text-sm font-medium text-gray-700 hover:bg-blue-50 hover:text-cab-blue transition-colors"
                      role="menuitem"
                    >
                      {link.label}
                    </button>
                  )}
                </li>
              ))}

              <li role="none">
                <button
                  onClick={() => {
                    // TODO: Ouvrir modal login
                    closeMobileMenu();
                  }}
                  className="w-full text-left px-4 py-3 rounded-xl text-sm font-medium text-gray-700 hover:bg-blue-50 hover:text-cab-blue transition-colors"
                  role="menuitem"
                >
                  🔑 Connexion
                </button>
              </li>

              <li role="none">
                <Link
                  href="/certification"
                  onClick={closeMobileMenu}
                  className="block w-full text-center px-4 py-3 bg-cab-blue text-white rounded-xl text-sm font-semibold hover:bg-cab-dark transition-colors"
                  role="menuitem"
                >
                  📝 Certification
                </Link>
              </li>
            </ul>
          </div>
        </>
      )}
    </>
  );
};

export default Navigation;
